{
  "name": "RoofPro Field Calculator",
  "description": "A high-contrast, mobile-first calculator for roofing professionals to quickly estimate square footage and material requirements for main roof areas and parapet walls."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum CalculatorTab {
  MAIN_AREA = 'MAIN_AREA',
  PERIMETER = 'PERIMETER'
}

export interface MaterialResult {
  label: string;
  value: number;
  unit: string;
}

export interface CalculationResults {
  baseSqft: number;
  totalSqftWithWaste: number;
  materials: MaterialResult[];
}

export interface PerimeterResults {
  totalPerimeter: number;
  wallFactor: number;
  wallSqft: number;
  materials: MaterialResult[];
}

import React from 'react';

interface NumberInputProps {
  label: string;
  value: string | number;
  onChange: (val: string) => void;
  placeholder?: string;
  suffix?: string;
}

export const NumberInput: React.FC<NumberInputProps> = ({ label, value, onChange, placeholder, suffix }) => {
  return (
    <div className="flex flex-col gap-1.5 w-full">
      <label className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
        {label}
      </label>
      <div className="relative">
        <input
          type="number"
          inputMode="decimal"
          value={value}
          onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder}
          className="w-full bg-slate-800 border-2 border-slate-700 text-white text-2xl font-bold p-4 rounded-xl focus:border-yellow-500 focus:outline-none transition-colors appearance-none"
        />
        {suffix && (
          <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 font-bold uppercase pointer-events-none">
            {suffix}
          </span>
        )}
      </div>
    </div>
  );
};

import React from 'react';

interface ResultCardProps {
  label: string;
  value: string | number;
  unit?: string;
  highlight?: boolean;
}

export const ResultCard: React.FC<ResultCardProps> = ({ label, value, unit, highlight }) => {
  return (
    <div className={`p-4 rounded-xl border-2 flex flex-col items-center justify-center transition-all ${
      highlight 
        ? 'bg-yellow-500 border-yellow-400 text-slate-900 shadow-lg shadow-yellow-500/20' 
        : 'bg-slate-800 border-slate-700 text-white'
    }`}>
      <span className={`text-[10px] uppercase font-bold tracking-widest mb-1 ${highlight ? 'text-slate-800' : 'text-slate-400'}`}>
        {label}
      </span>
      <div className="flex items-baseline gap-1">
        <span className="text-3xl font-black mono">{value}</span>
        {unit && <span className="text-xs font-bold uppercase">{unit}</span>}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { NumberInput } from './NumberInput';
import { ResultCard } from './ResultCard';

export const MainAreaCalculator: React.FC = () => {
  const [length, setLength] = useState<string>('');
  const [width, setWidth] = useState<string>('');

  const results = useMemo(() => {
    const l = parseFloat(length) || 0;
    const w = parseFloat(width) || 0;

    const baseSqft = l * w;
    const totalWithWaste = baseSqft * 1.1;

    return {
      baseSqft: Math.round(baseSqft),
      totalWithWaste: Math.ceil(totalWithWaste),
      iso4x4: Math.ceil(totalWithWaste / 16),
      iso4x8: Math.ceil(totalWithWaste / 32),
      board3x8: Math.ceil(totalWithWaste / 24),
      capRolls: Math.ceil(totalWithWaste / 75),
      baseRolls: Math.ceil(totalWithWaste / 99)
    };
  }, [length, width]);

  const handleReset = () => {
    setLength('');
    setWidth('');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <NumberInput label="Length" value={length} onChange={setLength} placeholder="0.00" suffix="FT" />
        <NumberInput label="Width" value={width} onChange={setWidth} placeholder="0.00" suffix="FT" />
      </div>

      <div className="grid grid-cols-2 gap-3">
        <ResultCard label="Base Area" value={results.baseSqft} unit="SQFT" />
        <ResultCard label="Area (+10%)" value={results.totalWithWaste} unit="SQFT" highlight />
      </div>

      <div className="space-y-4">
        <h3 className="text-sm font-bold text-slate-500 uppercase tracking-widest px-1 border-b border-slate-800 pb-2">
          Estimated Materials
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <span className="text-slate-300 font-semibold">4' x 4' ISO Board</span>
            <span className="text-2xl font-black text-yellow-500 mono">{results.iso4x4}</span>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <span className="text-slate-300 font-semibold">4' x 8' ISO Board</span>
            <span className="text-2xl font-black text-yellow-500 mono">{results.iso4x8}</span>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <span className="text-slate-300 font-semibold">3' x 8' Board</span>
            <span className="text-2xl font-black text-yellow-500 mono">{results.board3x8}</span>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <span className="text-slate-300 font-semibold">3' x 25' Cap Rolls</span>
            <span className="text-2xl font-black text-yellow-500 mono">{results.capRolls}</span>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <span className="text-slate-300 font-semibold">3' x 33' Base Rolls</span>
            <span className="text-2xl font-black text-yellow-500 mono">{results.baseRolls}</span>
          </div>
        </div>
      </div>

      <button 
        onClick={handleReset}
        className="w-full bg-slate-800 text-slate-400 font-bold p-4 rounded-xl border-2 border-slate-700 hover:text-white hover:border-slate-600 transition-all active:scale-95"
      >
        RESET ALL FIELDS
      </button>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { NumberInput } from './NumberInput';
import { ResultCard } from './ResultCard';

export const PerimeterCalculator: React.FC = () => {
  const [segments, setSegments] = useState<string[]>(Array(10).fill(''));
  const [parapetHeight, setParapetHeight] = useState<string>('');

  const results = useMemo(() => {
    const totalPerimeter = segments.reduce((acc, curr) => acc + (parseFloat(curr) || 0), 0);
    const height = parseFloat(parapetHeight) || 0;

    // Wall Factor: (Height + 16 inches) / 12
    const wallFactor = (height + 16) / 12;
    const wallSqft = totalPerimeter * wallFactor;

    return {
      totalPerimeter: Math.ceil(totalPerimeter),
      wallFactor: wallFactor.toFixed(2),
      wallSqft: Math.ceil(wallSqft),
      peelStick: Math.ceil(wallSqft / 100),
      capRolls: Math.ceil(wallSqft / 75),
      ffRolls: Math.ceil(wallSqft / 85)
    };
  }, [segments, parapetHeight]);

  const updateSegment = (index: number, value: string) => {
    const newSegments = [...segments];
    newSegments[index] = value;
    setSegments(newSegments);
  };

  const handleReset = () => {
    setSegments(Array(10).fill(''));
    setParapetHeight('');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 gap-4">
        <NumberInput label="Parapet Height" value={parapetHeight} onChange={setParapetHeight} placeholder="0" suffix="IN" />
      </div>

      <div className="space-y-4">
        <h3 className="text-sm font-bold text-slate-500 uppercase tracking-widest px-1 border-b border-slate-800 pb-2">
          Perimeter Segments (Linear FT)
        </h3>
        <div className="grid grid-cols-2 sm:grid-cols-5 gap-2">
          {segments.map((val, idx) => (
            <input
              key={idx}
              type="number"
              inputMode="decimal"
              value={val}
              onChange={(e) => updateSegment(idx, e.target.value)}
              placeholder={`Seg ${idx + 1}`}
              className="bg-slate-800 border border-slate-700 text-white text-lg font-bold p-3 rounded-lg focus:border-yellow-500 focus:outline-none text-center"
            />
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
        <ResultCard label="Total Perimeter" value={results.totalPerimeter} unit="FT" />
        <ResultCard label="Wall Factor" value={results.wallFactor} unit="X" />
        <ResultCard label="Wall Area" value={results.wallSqft} unit="SQFT" highlight />
      </div>

      <div className="space-y-4">
        <h3 className="text-sm font-bold text-slate-500 uppercase tracking-widest px-1 border-b border-slate-800 pb-2">
          Wall Materials
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
           <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex flex-col items-center">
            <span className="text-[10px] uppercase font-bold text-slate-400 mb-1">Peel & Stick Rolls</span>
            <span className="text-3xl font-black text-yellow-500 mono">{results.peelStick}</span>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex flex-col items-center">
            <span className="text-[10px] uppercase font-bold text-slate-400 mb-1">Cap Rolls</span>
            <span className="text-3xl font-black text-yellow-500 mono">{results.capRolls}</span>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex flex-col items-center">
            <span className="text-[10px] uppercase font-bold text-slate-400 mb-1">FF Rolls</span>
            <span className="text-3xl font-black text-yellow-500 mono">{results.ffRolls}</span>
          </div>
        </div>
      </div>

      <button 
        onClick={handleReset}
        className="w-full bg-slate-800 text-slate-400 font-bold p-4 rounded-xl border-2 border-slate-700 hover:text-white hover:border-slate-600 transition-all active:scale-95"
      >
        CLEAR ALL SEGMENTS
      </button>
    </div>
  );
};

