import React, { useMemo } from 'react';
import { NumberInput } from './NumberInput';
import { ResultCard } from './ResultCard';

interface Props {
  segments: string[];
  setSegments: (segs: string[]) => void;
  parapetHeight: string;
  setParapetHeight: (val: string) => void;
}

export const PerimeterCalculator: React.FC<Props> = ({ segments, setSegments, parapetHeight, setParapetHeight }) => {
  const results = useMemo(() => {
    const totalPerimeter = segments.reduce((acc, curr) => acc + (parseFloat(curr) || 0), 0);
    const height = parseFloat(parapetHeight) || 0;

    // Wall Factor: (Height + 16 inches) / 12
    const wallFactor = (height + 16) / 12;
    const wallSqft = totalPerimeter * wallFactor;

    return {
      totalPerimeter: Math.ceil(totalPerimeter),
      wallFactor: wallFactor.toFixed(2),
      wallSqft: Math.ceil(wallSqft),
      peelStick: Math.ceil(wallSqft / 100),
      capRolls: Math.ceil(wallSqft / 75),
      ffRolls: Math.ceil(wallSqft / 85)
    };
  }, [segments, parapetHeight]);

  const updateSegment = (index: number, value: string) => {
    const newSegments = [...segments];
    newSegments[index] = value;
    setSegments(newSegments);
  };

  const handleReset = () => {
    setSegments(Array(10).fill(''));
    setParapetHeight('');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 gap-4">
        <NumberInput label="Parapet Height" value={parapetHeight} onChange={setParapetHeight} placeholder="0" suffix="IN" />
      </div>

      <div className="space-y-4">
        <h3 className="text-sm font-bold text-slate-500 uppercase tracking-widest px-1 border-b border-slate-800 pb-2 italic">
          Perimeter Segments (Linear FT)
        </h3>
        <div className="grid grid-cols-2 sm:grid-cols-5 gap-2">
          {segments.map((val, idx) => (
            <input
              key={idx}
              type="number"
              inputMode="decimal"
              value={val}
              onChange={(e) => updateSegment(idx, e.target.value)}
              placeholder={`Seg ${idx + 1}`}
              className="bg-slate-800 border border-slate-700 text-white text-lg font-bold p-3 rounded-lg focus:border-yellow-500 focus:outline-none text-center"
            />
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
        <ResultCard label="Total Perimeter" value={results.totalPerimeter} unit="FT" />
        <ResultCard label="Wall Factor" value={results.wallFactor} unit="X" />
        <ResultCard label="Wall Area" value={results.wallSqft} unit="SQFT" highlight />
      </div>

      <div className="space-y-4">
        <h3 className="text-sm font-bold text-slate-500 uppercase tracking-widest px-1 border-b border-slate-800 pb-2 italic">
          Wall Materials
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
           <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex flex-col items-center">
            <span className="text-[10px] uppercase font-bold text-slate-400 mb-1">Peel & Stick Rolls</span>
            <span className="text-3xl font-black text-yellow-500 mono">{results.peelStick}</span>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex flex-col items-center">
            <span className="text-[10px] uppercase font-bold text-slate-400 mb-1">Cap Rolls</span>
            <span className="text-3xl font-black text-yellow-500 mono">{results.capRolls}</span>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 flex flex-col items-center">
            <span className="text-[10px] uppercase font-bold text-slate-400 mb-1">FF Rolls</span>
            <span className="text-3xl font-black text-yellow-500 mono">{results.ffRolls}</span>
          </div>
        </div>
      </div>

      <button 
        onClick={handleReset}
        className="w-full bg-slate-800 text-slate-400 font-bold p-4 rounded-xl border-2 border-slate-700 hover:text-white hover:border-slate-600 transition-all active:scale-95 text-xs uppercase tracking-widest"
      >
        CLEAR ALL SEGMENTS
      </button>
    </div>
  );
};

import React, { useMemo, useState, useEffect } from 'react';

interface Props {
  areaLength: string;
  areaWidth: string;
  perimeterSegments: string[];
  parapetHeight: string;
}

export const MaterialList: React.FC<Props> = ({ 
  areaLength, 
  areaWidth, 
  perimeterSegments, 
  parapetHeight 
}) => {
  const [email, setEmail] = useState<string>(() => localStorage.getItem('roof_pro_saved_email') || '');

  useEffect(() => {
    localStorage.setItem('roof_pro_saved_email', email);
  }, [email]);

  const materials = useMemo(() => {
    // Area calcs
    const al = parseFloat(areaLength) || 0;
    const aw = parseFloat(areaWidth) || 0;
    const baseSqft = al * aw;
    const areaTotalWithWaste = Math.ceil(baseSqft * 1.1);

    // Perimeter calcs
    const totalPerimeter = perimeterSegments.reduce((acc, curr) => acc + (parseFloat(curr) || 0), 0);
    const height = parseFloat(parapetHeight) || 0;
    const wallFactor = (height + 16) / 12;
    const wallSqft = Math.ceil(totalPerimeter * wallFactor);

    return {
      summary: {
        mainAreaSqft: areaTotalWithWaste,
        wallAreaSqft: wallSqft,
        totalPerimeter: Math.ceil(totalPerimeter)
      },
      list: [
        { name: "4' x 4' ISO Board", count: Math.ceil(areaTotalWithWaste / 16) },
        { name: "4' x 8' ISO Board", count: Math.ceil(areaTotalWithWaste / 32) },
        { name: "3' x 8' Board", count: Math.ceil(areaTotalWithWaste / 24) },
        { name: "Cap Rolls (Main Area)", count: Math.ceil(areaTotalWithWaste / 75) },
        { name: "Base Rolls (Main Area)", count: Math.ceil(areaTotalWithWaste / 96) },
        { name: "Peel & Stick Rolls (Wall)", count: Math.ceil(wallSqft / 100) },
        { name: "Cap Rolls (Wall)", count: Math.ceil(wallSqft / 75) },
        { name: "FF Rolls (Wall)", count: Math.ceil(wallSqft / 85) }
      ].filter(item => item.count > 0)
    };
  }, [areaLength, areaWidth, perimeterSegments, parapetHeight]);

  const handleSendEmail = () => {
    if (!email) {
      alert("Please enter a destination email address first.");
      return;
    }

    const date = new Date().toLocaleDateString();
    const subject = `Roof Material List - ${date}`;

    let body = `Material List Exported from JustinRoofPRO\n`;
    body += `Date: ${date}\n\n`;
    body += `--- PROJECT DETAILS ---\n`;
    body += `Main Area: ${materials.summary.mainAreaSqft} SQFT (+10%)\n`;
    body += `Wall Area: ${materials.summary.wallAreaSqft} SQFT\n`;
    body += `Total Perimeter: ${materials.summary.totalPerimeter} FT\n\n`;
    body += `--- MATERIALS NEEDED ---\n`;
    materials.list.forEach(item => {
      body += `- ${item.name}: ${item.count}\n`;
    });
    body += `\nSent via JustinRoofPRO Field Tool`;

    const mailtoUrl = `mailto:${email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    window.location.href = mailtoUrl;
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900 border border-slate-700 p-5 rounded-3xl space-y-4">
        <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] italic">Saved Export Email</label>
        <div className="relative">
          <input 
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="orders@company.com"
            className="w-full bg-slate-800 border-2 border-slate-700 text-white p-4 rounded-2xl focus:border-yellow-500 focus:outline-none transition-all font-bold"
          />
          <div className="absolute right-4 top-1/2 -translate-y-1/2 text-yellow-500/50">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path d="M2.003 5.884L10 9.882l7.997-3.998A2 2 0 0016 4H4a2 2 0 00-1.997 1.884z" />
              <path d="M18 8.118l-8 4-8-4V14a2 2 0 002 2h12a2 2 0 002-2V8.118z" />
            </svg>
          </div>
        </div>
      </div>

      <div className="bg-slate-900/50 p-6 rounded-[2.5rem] border border-slate-800/50 space-y-6">
        <div className="flex justify-between items-center px-2">
          <h3 className="text-sm font-black text-white uppercase tracking-widest italic">Review Order</h3>
          <span className="bg-yellow-500 text-slate-950 text-[10px] font-black px-2 py-1 rounded italic">
            {materials.list.length} ITEMS
          </span>
        </div>

        {materials.list.length === 0 ? (
          <div className="text-center py-8">
            <p className="text-slate-600 text-xs font-bold uppercase tracking-widest">No materials calculated yet</p>
            <p className="text-slate-700 text-[10px] mt-2 italic">Enter dimensions in other tabs first</p>
          </div>
        ) : (
          <div className="space-y-2">
            {materials.list.map((item, idx) => (
              <div key={idx} className="flex justify-between items-center p-4 bg-slate-950/40 rounded-2xl border border-slate-800/30">
                <span className="text-slate-300 font-bold text-xs uppercase tracking-tight">{item.name}</span>
                <span className="text-xl font-black text-yellow-500 mono">{item.count}</span>
              </div>
            ))}
          </div>
        )}

        <button 
          onClick={handleSendEmail}
          disabled={materials.list.length === 0}
          className={`w-full py-5 rounded-2xl font-black uppercase tracking-tighter flex items-center justify-center gap-3 transition-all active:scale-95 shadow-2xl ${
            materials.list.length === 0 
